import React, { useState, useRef } from "react";

const STYLE = `
  @import url('https://fonts.googleapis.com/css2?family=DM+Serif+Display&family=DM+Sans:wght@400;500;600&family=DM+Mono&display=swap');

  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --bg:     #F5F3EF;
    --ink:    #1A1A18;
    --muted:  #7A7A72;
    --accent: #1B4B8A;
    --accent-dark: #163d73;
    --surface: #FFFFFF;
    --border: #E2DFD8;
    --radius: 10px;
    --max: 760px;
  }

  body {
    background: var(--bg);
    color: var(--ink);
    font-family: 'DM Sans', sans-serif;
    font-size: 16px;
    line-height: 1.6;
  }

  .wrap { max-width: var(--max); margin: 0 auto; padding: 0 20px; }

  /* NAV */
  nav {
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    padding: 14px 0;
    position: sticky;
    top: 0;
    z-index: 100;
  }
  nav .wrap { display: flex; align-items: center; justify-content: space-between; }
  .nav-brand { font-family: 'DM Serif Display', serif; font-size: 1.4rem; color: var(--accent); text-decoration: none; }
  .nav-tag { font-size: 0.78rem; color: var(--muted); }

  /* HERO */
  .hero { padding: 60px 0 40px; text-align: center; }
  .hero h1 { font-family: 'DM Serif Display', serif; font-size: clamp(2rem, 5vw, 3rem); line-height: 1.15; margin-bottom: 16px; }
  .hero p { font-size: 1.1rem; color: var(--muted); max-width: 520px; margin: 0 auto 32px; }

  /* DECODER CARD */
  .card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: var(--radius);
    padding: 32px;
    margin-bottom: 24px;
  }

  .card label { display: block; font-weight: 600; margin-bottom: 8px; }

  .card textarea {
    width: 100%;
    min-height: 130px;
    padding: 12px;
    border: 1px solid var(--border);
    border-radius: 6px;
    font-family: 'DM Mono', monospace;
    font-size: 0.88rem;
    resize: vertical;
    background: var(--bg);
    color: var(--ink);
  }

  .card textarea:focus { outline: 2px solid var(--accent); }

  .btn {
    display: inline-block;
    background: var(--accent);
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 12px 28px;
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    margin-top: 14px;
    transition: background 0.15s;
  }
  .btn:hover { background: var(--accent-dark); }
  .btn:disabled { opacity: 0.6; cursor: not-allowed; }

  /* RESULT */
  .result {
    background: var(--surface);
    border: 1px solid var(--border);
    border-left: 4px solid var(--accent);
    border-radius: var(--radius);
    padding: 28px 32px;
    margin-bottom: 24px;
    font-size: 0.97rem;
    line-height: 1.75;
    white-space: pre-wrap;
  }

  /* EXAMPLES */
  .examples { margin-bottom: 48px; }
  .examples h2 { font-family: 'DM Serif Display', serif; font-size: 1.4rem; margin-bottom: 16px; }
  .chip-row { display: flex; flex-wrap: wrap; gap: 10px; }
  .chip {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 20px;
    padding: 7px 16px;
    font-size: 0.85rem;
    cursor: pointer;
    transition: border-color 0.15s, color 0.15s;
  }
  .chip:hover { border-color: var(--accent); color: var(--accent); }

  /* FOOTER */
  footer {
    border-top: 1px solid var(--border);
    padding: 28px 0;
    text-align: center;
    font-size: 0.82rem;
    color: var(--muted);
  }
  .footer-brand { font-weight: 600; color: var(--ink); }
  .footer-note { margin-top: 4px; }

  @media (max-width: 600px) {
    .card { padding: 20px; }
    .result { padding: 20px; }
  }
`;

const EXAMPLES = [
  "What does a deductible mean on my health insurance?",
  "Explain what 'out-of-pocket maximum' means",
  "What is the difference between HMO and PPO?",
  "My claim was denied — what does 'not medically necessary' mean?",
  "What does 'coordination of benefits' mean?",
  "Explain what a co-pay vs coinsurance is",
  "What is a pre-existing condition exclusion?",
  "What does 'subrogation' mean in an insurance policy?",
];

export default function App() {
  const [input, setInput] = useState("");
  const [output, setOutput] = useState("");
  const [loading, setLoading] = useState(false);
  const resultRef = useRef(null);

  async function decode() {
    if (!input.trim()) return;
    setLoading(true);
    setOutput("");

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "x-api-key": process.env.REACT_APP_ANTHROPIC_API_KEY,
          "anthropic-version": "2023-06-01",
          "anthropic-dangerous-direct-browser-access": "true",
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-5",
          max_tokens: 1024,
          messages: [
            {
              role: "user",
              content: `You are InsurePlain, a plain-English insurance educator. Explain the following insurance term, clause, or situation in clear, simple language that any policyholder can understand. Do not give legal advice or guarantee coverage outcomes. Always note that actual coverage depends on the individual policy, insurer, state, and circumstances. Readers should consult their policy documents or a licensed insurance professional for specific guidance.\n\n${input}`,
            },
          ],
        }),
      });

      const data = await res.json();
      const text = data?.content?.[0]?.text ?? "No response received.";
      setOutput(text);
      setTimeout(() => resultRef.current?.scrollIntoView({ behavior: "smooth" }), 100);
    } catch (err) {
      setOutput("Something went wrong. Please try again.");
    } finally {
      setLoading(false);
    }
  }

  return (
    <>
      <style>{STYLE}</style>

      <nav>
        <div className="wrap">
          <a href="/" className="nav-brand">InsurePlain</a>
          <span className="nav-tag">Insurance in plain English</span>
        </div>
      </nav>

      <main className="wrap">
        <div className="hero">
          <h1>Understand your insurance.<br />No agent required.</h1>
          <p>Paste any insurance term, clause, or denial reason and get a plain-English explanation in seconds.</p>
        </div>

        <div className="card">
          <label htmlFor="input">Paste your insurance question or term</label>
          <textarea
            id="input"
            placeholder="e.g. What does 'out-of-pocket maximum' mean? Or paste a denial reason..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button className="btn" onClick={decode} disabled={loading}>
            {loading ? "Decoding…" : "Decode →"}
          </button>
        </div>

        {output && (
          <div className="result" ref={resultRef}>
            {output}
          </div>
        )}

        <div className="examples">
          <h2>Try an example</h2>
          <div className="chip-row">
            {EXAMPLES.map((ex) => (
              <button key={ex} className="chip" onClick={() => setInput(ex)}>
                {ex}
              </button>
            ))}
          </div>
        </div>
      </main>

      <footer>
        <div className="wrap">
          <span className="footer-brand">insureplain.com</span>
          <div className="footer-note">Not a substitute for professional insurance advice.</div>
        </div>
      </footer>
    </>
  );
}
